import{_ as e,o as n,c as i,ag as l}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"[Thiết kế Chi tiết] Quản trị Điểm đến (POI Management)","description":"","frontmatter":{},"headers":[],"relativePath":"05-quan-ly-sprint/sprint-2-quan-tri-diem-den/04-thiet-ke-chi-tiet-poi.md","filePath":"05-quan-ly-sprint/sprint-2-quan-tri-diem-den/04-thiet-ke-chi-tiet-poi.md"}'),a={name:"05-quan-ly-sprint/sprint-2-quan-tri-diem-den/04-thiet-ke-chi-tiet-poi.md"};function s(d,t,h,r,o,g){return n(),i("div",null,[...t[0]||(t[0]=[l(`<h1 id="thiet-ke-chi-tiet-quan-tri-điem-đen-poi-management" tabindex="-1">[Thiết kế Chi tiết] Quản trị Điểm đến (POI Management) <a class="header-anchor" href="#thiet-ke-chi-tiet-quan-tri-điem-đen-poi-management" aria-label="Permalink to &quot;[Thiết kế Chi tiết] Quản trị Điểm đến (POI Management)&quot;">​</a></h1><table tabindex="0"><thead><tr><th style="text-align:left;">Phiên bản</th><th style="text-align:left;">Ngày</th><th style="text-align:left;">Sprint</th><th style="text-align:left;">Nội dung thay đổi</th><th style="text-align:left;">Người thực hiện</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>v1.0</strong></td><td style="text-align:left;">26/03/2026</td><td style="text-align:left;"><a href="./../../02-quan-ly-sprint/sprint-2-quan-tri-diem-den/01-yeu-cau-nghiep-vu">Sprint 2</a></td><td style="text-align:left;">Khởi tạo tài liệu thiết kế chi tiết</td><td style="text-align:left;">PO</td></tr></tbody></table><hr><p>Tài liệu thiết kế chi tiết cho module Điểm đến, phục vụ Dev trong quá trình lập trình và QA/Tester trong quá trình kiểm thử.</p><h2 id="_1-so-đo-luong-nghiep-vu-flowchart" tabindex="-1">1. Sơ đồ Luồng Nghiệp vụ (Flowchart) <a class="header-anchor" href="#_1-so-đo-luong-nghiep-vu-flowchart" aria-label="Permalink to &quot;1. Sơ đồ Luồng Nghiệp vụ (Flowchart)&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[Admin truy cập List] --&gt; B{Nhấn Thêm mới?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B -- Yes --&gt; C[Hiển thị Form]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[Nhập Tên / Chọn Vùng]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[Tự động tạo Slug]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[Upload Hình ảnh]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; G{Nhấn Lưu?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G -- Yes --&gt; H[Backend Validate]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    H -- Hợp lệ --&gt; I[Lưu Database &amp; Cloudinary]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    H -- Lỗi --&gt; J[Hiển thị Toast Lỗi]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    I --&gt; K[Trở về trang List]</span></span></code></pre></div><h2 id="_2-cau-truc-truong-du-lieu-field-specs" tabindex="-1">2. Cấu trúc trường dữ liệu (Field Specs) <a class="header-anchor" href="#_2-cau-truc-truong-du-lieu-field-specs" aria-label="Permalink to &quot;2. Cấu trúc trường dữ liệu (Field Specs)&quot;">​</a></h2><p>Bảng dữ liệu: <code>Destination</code></p><table tabindex="0"><thead><tr><th style="text-align:left;">Tên trường</th><th style="text-align:left;">Kiểu dữ liệu</th><th style="text-align:center;">Bắt buộc</th><th style="text-align:left;">Ràng buộc</th><th style="text-align:left;">Mô tả</th></tr></thead><tbody><tr><td style="text-align:left;"><code>id</code></td><td style="text-align:left;">String</td><td style="text-align:center;">Yes</td><td style="text-align:left;">Primary Key (uuid)</td><td style="text-align:left;">Định danh duy nhất</td></tr><tr><td style="text-align:left;"><code>nameVi</code></td><td style="text-align:left;">String</td><td style="text-align:center;">Yes</td><td style="text-align:left;">Max 100 ký tự</td><td style="text-align:left;">Tên tiếng Việt hiển thị</td></tr><tr><td style="text-align:left;"><code>nameEn</code></td><td style="text-align:left;">String</td><td style="text-align:center;">No</td><td style="text-align:left;">Max 100 ký tự</td><td style="text-align:left;">Tên tiếng Anh (mặc định=nameVi)</td></tr><tr><td style="text-align:left;"><code>slug</code></td><td style="text-align:left;">String</td><td style="text-align:center;">Yes</td><td style="text-align:left;">Unique, ASCII-only</td><td style="text-align:left;">URL thân thiện (e.g. vinh-ha-long)</td></tr><tr><td style="text-align:left;"><code>regionId</code></td><td style="text-align:left;">String</td><td style="text-align:center;">Yes</td><td style="text-align:left;">Foreign Key</td><td style="text-align:left;">Liên kết tới bảng <code>Region</code></td></tr><tr><td style="text-align:left;"><code>imageUrl</code></td><td style="text-align:left;">String</td><td style="text-align:center;">No</td><td style="text-align:left;">URL Cloudinary</td><td style="text-align:left;">Ảnh đại diện chính</td></tr><tr><td style="text-align:left;"><code>description</code></td><td style="text-align:left;">Text</td><td style="text-align:center;">No</td><td style="text-align:left;">Rich-text</td><td style="text-align:left;">Mô tả chi tiết (HTML)</td></tr><tr><td style="text-align:left;"><code>isFeatured</code></td><td style="text-align:left;">Boolean</td><td style="text-align:center;">Yes</td><td style="text-align:left;">Default: false</td><td style="text-align:left;">Trạng thái nổi bật</td></tr><tr><td style="text-align:left;"><code>sortOrder</code></td><td style="text-align:left;">Int</td><td style="text-align:center;">Yes</td><td style="text-align:left;">Default: 0</td><td style="text-align:left;">Thứ tự sắp xếp hiển thị</td></tr></tbody></table><h2 id="_3-đac-ta-thanh-phan-ui-component-specs" tabindex="-1">3. Đặc tả Thành phần UI (Component Specs) <a class="header-anchor" href="#_3-đac-ta-thanh-phan-ui-component-specs" aria-label="Permalink to &quot;3. Đặc tả Thành phần UI (Component Specs)&quot;">​</a></h2><h3 id="_3-1-bilingualinput-o-nhap-lieu-song-ngu" tabindex="-1">3.1. [BilingualInput] - Ô nhập liệu song ngữ <a class="header-anchor" href="#_3-1-bilingualinput-o-nhap-lieu-song-ngu" aria-label="Permalink to &quot;3.1. [BilingualInput] - Ô nhập liệu song ngữ&quot;">​</a></h3><ul><li><strong>Mô tả</strong>: Cho phép nhập liệu <code>nameVi</code> và <code>nameEn</code> đồng thời.</li><li><strong>Props</strong>: <code>label</code>, <code>required</code>, <code>valueVi</code>, <code>valueEn</code>.</li><li><strong>Hành vi</strong>: Nếu <code>nameEn</code> để trống, hệ thống tự động copy giá trị từ <code>nameVi</code>.</li></ul><h3 id="_3-2-imageuploader-trinh-tai-len-hinh-anh" tabindex="-1">3.2. [ImageUploader] - Trình tải lên hình ảnh <a class="header-anchor" href="#_3-2-imageuploader-trinh-tai-len-hinh-anh" aria-label="Permalink to &quot;3.2. [ImageUploader] - Trình tải lên hình ảnh&quot;">​</a></h3><ul><li><strong>Mô tả</strong>: Tích hợp Cloudinary SDK để tải ảnh trực tiếp từ trình duyệt.</li><li><strong>Hành vi</strong>: <ul><li>Hiển thị Skeleton loading khi đang upload.</li><li>Hiển thị nút &quot;Xóa&quot; đè lên ảnh sau khi upload thành công.</li><li>Validate file size: Max 5MB.</li></ul></li></ul><h3 id="_3-3-sluggenerator-trinh-tao-đuong-dan" tabindex="-1">3.3. [SlugGenerator] - Trình tạo đường dẫn <a class="header-anchor" href="#_3-3-sluggenerator-trinh-tao-đuong-dan" aria-label="Permalink to &quot;3.3. [SlugGenerator] - Trình tạo đường dẫn&quot;">​</a></h3><ul><li><strong>Logic</strong>: Sử dụng thư viện <code>slugify</code> để chuyển <code>Tiếng Việt</code> -&gt; <code>tieng-viet</code>.</li><li><strong>Hành vi</strong>: Update real-time khi gõ <code>nameVi</code>. Cho phép &quot;Unlock&quot; để sửa thủ công nếu cần.</li></ul><h2 id="_4-xu-ly-loi-trang-thai-error-handling" tabindex="-1">4. Xử lý Lỗi &amp; Trạng thái (Error Handling) <a class="header-anchor" href="#_4-xu-ly-loi-trang-thai-error-handling" aria-label="Permalink to &quot;4. Xử lý Lỗi &amp; Trạng thái (Error Handling)&quot;">​</a></h2><ul><li><strong>Lỗi 409 (Conflict)</strong>: Trùng mã slug -&gt; Hiển thị &quot;Đường dẫn đã tồn tại&quot;.</li><li><strong>Lỗi 400 (Bad Request)</strong>: Vùng miền chưa được chọn -&gt; Hiển thị &quot;Vui lòng chọn Vùng miền&quot;.</li></ul><hr><p><em>Ghi chú: API kết nối xem tại <a href="./05-api-design">API Design Docs</a>.</em></p>`,20)])])}const p=e(a,[["render",s]]);export{u as __pageData,p as default};
